80	  it.todo("regular sword (steel, ench 3), damage 500 G → payout 400 G (full minus 100 deductible)");
81	  it.todo("damage to a rune (insurance value 250 G), damage 200 G → payout 100 G (full minus 100 deductible; no special clause)");
