87	  it.todo("dragon-material sword, enchantment 8, damage 1000 G → payout 400 G (high-enchantment clause: 50%, then deductible)");
88	  it.todo("dragon-material sword, enchantment 9, damage 1000 G → payout 400 G (50% rule wins over dragon material, then deductible: 500 - 100)");
89	  it.todo("dragon-material sword, enchantment 5, damage 800 G → payout 700 G (only dragon-material clause: full, then deductible: 800 - 100)");
