91	
92	  // --- Multiple items of the same type (❓ two swords) ---
93	  it.todo("policy covers two swords → insurance sum 2000 G (= 2 x 1000)");
94	  it.todo("dragon attack damages both swords; each damages entry treated as separate damage with own deductible");
95	  it.todo("damages array contains more entries of a type than the policy covers → whole claim rejected (non-zero exit)");
96	
