98	  it.todo("quote includes item with unknown type (e.g. broomstick) → non-zero exit, error on stderr, no results on stdout");
99	  it.todo("claim references damage entry for an item not part of the policy (e.g. amulet damaged when only sword insured) → non-zero exit, error on stderr");
100	  it.todo("claim references damage entry with unknown item type → non-zero exit, error on stderr");
101	  it.todo("claim contains a damage entry with amount -200 → non-zero exit, error on stderr");
102	
103	  // --- CLI integration (reads JSON from stdin, writes results to stdout) ---
104	  it.todo("CLI scenario with a quote step writes {results: [{premium: N}]} to stdout");
105	  it.todo("CLI scenario with quote followed by claim referencing policy by zero-based step index produces results in same order as steps");
106	});
